class Solution:
    def maxEnergyBoost(self, energyDrinkA, energyDrinkB):
        import sys
        sys.setrecursionlimit(1000000)
        A, B = energyDrinkA, energyDrinkB
        n = len(A)
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def rec(i, cur):
            if i == n:
                return 0
            best = 0
            if cur != 1:
                best = max(best, A[i] + rec(i + 1, 0))
            if cur != 0:
                best = max(best, B[i] + rec(i + 1, 1))
            if cur == 0:
                best = max(best, rec(i + 1, 1))
            elif cur == 1:
                best = max(best, rec(i + 1, 0))
            return best

        result = rec(0, -1)
        rec.cache_clear()
        return result

