class Solution:
    def maxEnergyBoost(self, energyDrinkA, energyDrinkB):
        n = len(energyDrinkA)
        dpA = [0] * n
        dpB = [0] * n
        dpA[0] = energyDrinkA[0]
        dpB[0] = energyDrinkB[0]
        for i in range(1, n):
            lookbackA = dpB[i - 2] if i >= 2 else 0
            lookbackB = dpA[i - 2] if i >= 2 else 0
            dpA[i] = energyDrinkA[i] + max(dpA[i - 1], lookbackA)
            dpB[i] = energyDrinkB[i] + max(dpB[i - 1], lookbackB)
        return max(dpA[-1], dpB[-1])

