var maxEnergyBoost = function(energyDrinkA, energyDrinkB) {
    const n = energyDrinkA.length;
    const dpA = new Array(n).fill(0);
    const dpB = new Array(n).fill(0);
    dpA[0] = energyDrinkA[0];
    dpB[0] = energyDrinkB[0];
    for (let i = 1; i < n; i++) {
        const lookbackA = i >= 2 ? dpB[i - 2] : 0;
        const lookbackB = i >= 2 ? dpA[i - 2] : 0;
        dpA[i] = energyDrinkA[i] + Math.max(dpA[i - 1], lookbackA);
        dpB[i] = energyDrinkB[i] + Math.max(dpB[i - 1], lookbackB);
    }
    return Math.max(dpA[n - 1], dpB[n - 1]);
};
